import React, { useEffect, useState } from 'react';
import { useTrail, animated } from '@react-spring/web';
import Icon from './Icon';
import icons from '../config/iconExps';

interface ExpsProps {
  toggle: boolean;
}

/** Temps pour laisser finir le trail + ressorts avant démontage (14 icônes × trail + amortissement). */
const CLOSE_UNMOUNT_MS = 1600;

const Exps = ({ toggle }: ExpsProps) => {
  const expsTrail = useTrail(icons.length, {
    from: { x: -150 },
    to: { x: toggle ? 0 : -150 },
    config: { tension: 305, friction: 19, mass: 0.58 },
    trail: 48,
    delay: toggle ? 210 : 0,
  });

  const [display, setDisplay] = useState(false);

  useEffect(() => {
    if (toggle && !display) {
      setDisplay(true);
    }
    if (!toggle && display) {
      const t = setTimeout(() => {
        setDisplay(false);
      }, CLOSE_UNMOUNT_MS);
      return () => clearTimeout(t);
    }
  }, [display, toggle]);

  return (
    <div className="relative left-[45px] top-[10px] flex h-[100px] w-[600px] flex-row flex-wrap items-center justify-start p-[5px] max-[750px]:left-0 max-[750px]:top-5 max-[750px]:h-[100px] max-[750px]:w-[280px] max-[750px]:flex-wrap max-[750px]:justify-start">
      {display &&
        expsTrail.map((styles, index) => (
          <animated.div
            key={index}
            style={{
              transform: styles.x.to((x: number) => `translateX(${x}px)`),
              willChange: 'transform',
            }}
          >
            <Icon
              name={icons[index].name}
              title={icons[index].title}
              url={icons[index].url}
              background={false}
            />
          </animated.div>
        ))}
    </div>
  );
};

export default Exps;
